// Worked focus: cmem-pool-free-list-integrity — Maintain free-list membership, generation, duplicate-release, and exhaustion invariants.
/* Evidence: cmem-worked-cmem-arenas-pools-slabs-3 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 1279; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


struct arena_model { size_t used; size_t capacity; size_t high_water; };

static int worked_cmem_arenas_pools_slabs_3(struct arena_model *arena, size_t bytes, size_t alignment, size_t *offset) {
  size_t padding;
  if (arena == NULL || offset == NULL || alignment == 0) return 0;
  padding = (alignment - (arena->used % alignment)) % alignment;
  if (padding > arena->capacity - arena->used) return 0;
  if (bytes > arena->capacity - arena->used - padding) return 0;
  *offset = arena->used + padding;
  arena->used = *offset + bytes;
  if (arena->used > arena->high_water) arena->high_water = arena->used;
  return 1;
}

int main(void) {
  struct arena_model arena = { 3, 32, 3 };
  size_t offset = 0;
  int accepted = worked_cmem_arenas_pools_slabs_3(&arena, 5, 4, &offset);
  int rejected = worked_cmem_arenas_pools_slabs_3(&arena, 40, 8, &offset);
  int invariant = accepted && !rejected && arena.high_water <= arena.capacity;
  printf("arena used=%lu invariant=%d\n", (unsigned long)arena.used, invariant);
  return invariant ? 0 : 1;
}

